declare @c char(1), @d char(1)
select @c = char(253), @d = char(252)
select * into #t from dbo.FastBusiness$Function$System$Split(@@queryString, @c)
declare @ma_kh varchar(128), @ngay_ct1 smalldatetime, @ngay_ct2 smalldatetime, @ma_dvcs varchar(8000), @loai_ct char(1)

select @ma_dvcs = replace(data, @d, '''') from #t where id = 1
select @ma_kh = replace(data, @d, '''') from #t where id = 2
select @ngay_ct1 = data from #t where id = 3
select @ngay_ct2 = data from #t where id = 4
select @loai_ct = data from #t where id = 5

if @ma_dvcs = '' set @ma_dvcs = @@unit


declare @queryWhereClause nvarchar(4000), @queryFormClause nvarchar(4000), @ext varchar(3), @controllerFlowMulti varchar(64)
select @ext = case when @loai_ct = '1' then '71' when @loai_ct = '2' then '72' else '78' end
select @controllerFlowMulti = case when @loai_ct = '1' then 'PVFlowMultiGrid' when @loai_ct = '2' then 'PMFlowMultiGrid' else 'PGFlowMultiGrid' end
select @queryFormClause = 'm' + @ext + '$%Partition m with(nolock) join d' + @ext + '$%Partition a with(nolock) on m.stt_rec = a.stt_rec left join dmvt b on a.ma_vt = b.ma_vt'
select @queryWhereClause = 'm.ma_dvcs = ''' + replace(rtrim(@ma_dvcs), '''', '''''') + ''' and m.ma_kh like ''' + replace(rtrim(@ma_kh), '''', '''''') + '%'' and m.status in(''1'', ''2'')'
if exists(select 1 from syssiterights r where r.user_id = @@userID) begin
  select @queryWhereClause = @queryWhereClause + ' and exists(select 1 from syssiterights r where r.user_id = @@userID and a.ma_kho = r.ma_kho)'
end


declare @$primeAlias varchar(32), @$primeJoin varchar(4000), @$primeFilter nvarchar(4000), @$detailPartition varchar(4000), @$detailAlias varchar(4000), @$detailFilter nvarchar(4000)
create table #_f(i int identity(1, 1), datasource varchar(32), type tinyint, filterkey nvarchar(4000), alias varchar(32), xtype tinyint, refKey varchar(128), exRefKey varchar(128), refdatasource varchar(32), refalias varchar(32), fieldKey varchar(128), joinClause varchar(512))
select @$primeAlias = '', @$primeJoin = '', @$primeFilter = '', @$detailPartition = '', @$detailAlias = '', @$detailFilter = ''

if object_id('tempdb..#filter') is not null begin
  insert into #_f(datasource, type, filterkey, xtype, refKey, exRefKey, refdatasource, fieldKey, joinClause)
    select isnull(b.xtable, ''), '1', replace(case when b.conditionalreplace is null then a.conditional else replace(a.conditional, char(255) + a.field, replace(b.conditionalreplace, a.field + '%2', a.field + '%l')) end, char(255) + a.field, case when charindex(char(254), isnull(b.exname, '')) > 0 then '' else '%[a].' end + isnull(replace(replace(b.exname, '%2', '%l'), char(254), ''), a.field)), case when b.conditionalreplace is null then a.type else 0 end, b.fieldkey, b.exfieldkey, b.reftable, b.reffieldkey, isnull(b.joinclause, '')
      from #filter a join @@sysDatabaseName..sysfilterdeclares b on b.controller = @controllerFlowMulti and a.field = replace(b.name, '%2', '%l')
end

if exists(select 1 from #_f) exec FastBusiness$System$GetDynamicFilter @@userID, @@admin, @$primeAlias output, @$primeJoin output, @$primeFilter output, @$detailPartition output, @$detailAlias output, @$detailFilter output

&FilterQuery;
        &FlowMultiGridFinding;







function init$FlowMulti$GridQuery$&Identity;(g) {
  var f = g._$parentForm, c = String.fromCharCode(253), a = f._$queryFilterString.split(c);
  g._alterTitle = [null, [['%d1', formatDateView(a[2]), true], ['%d2', formatDateView(a[3]), true]]];
}

function load$FlowMulti$GridQuery$&Identity;(g) {
  g._$t = g._getColumnOrder('chon');
  g._$k = [];
  g._$f = ['stt_rec', 'stt_rec0'];
  g._$i = [g._getColumnOrder('stt_rec'), g._getColumnOrder('stt_rec0')];
  g._$s = [g._getColumnOrder('so_luong0')];
}
function dispose$FlowMulti$GridQuery$&Identity;(g) {g._$t = g._$k = g._$f = g._$i = g._$s =null;}
function scatter$FlowMulti$GridQuery$&Identity;(g) {scatter$FlowMulti$GridQuery(g);}

function toggle$FlowMulti$GridQuery$&Identity;(o) {
  var c = o.parentNode.parentNode.parentNode.id, g = $find($func.left(c, c.length - 11)), l = g._getColumnOrder('chon');
  var f = g.get_element().parentForm;

  for (var r = 1; r <= g._rowCount; r++) {
    if (!g._getItem(r, l).disabled) {
      g._setItemValue(r, l, !g._getItemValue(r, l));
      var o = g._getItem(r, l);
	    g._setItemValue(r, g._getColumnOrder('so_luong0'), o.checked ? g._getItemValue(r, g._getColumnOrder('so_luong')) : 0);
      if (o.checked) addTagRow$FlowMulti$(g, r);
        else removeTagRow$FlowMulti$(g, r);
    }
  }

  if (g._rowCount <= 0) return;
  else {
    g._activeRow = g._rowCount;
    g._activeColumn = l;
    g._activeCell = g._getItem(g._activeRow, g._activeColumn);
  }
}

function onClick$FlowMulti$GridQuery$&Identity;Calculate(o) {
  var g = o.grid, a = o.id.split('_inputCell_'), r = a[1].split('.')[0];
  if (!g) g = $find(a[0]);
  g._setItemValue(r, g._getColumnOrder('so_luong0'), o.checked ? g._getItemValue(r, g._getColumnOrder('so_luong')) : 0);
  if (o.checked) addTagRow$FlowMulti$(g, r);
  else removeTagRow$FlowMulti$(g, r);
}

function onChange$FlowMulti$GridQuery$&Identity;InvoiceQuantity(o) {
  var g = o.grid, a = o.id.split('_inputCell_'), r = a[1].split('.')[0];
  var l = g._getColumnOrder('chon'), v = g._getItemValue(r, l);
  if (v || o.value != 0) addTagRow$FlowMulti$(g, r);
  else removeTagRow$FlowMulti$(g, r);
}




